/**
 * Recebe items contendo campos Redis1 e Redis2 como strings JSON de arrays de mensagens.
 * Analisa ambos, une apenas as mensagens diferentes (sem duplicatas) e retorna uma única string.
 */
function mergeUniqueMessages(items) {
  // Obtém as strings brutas
  const raw1 = items[0].json.Redis1;
  const raw2 = items[0].json.Redis2;

  // Função para parsear com segurança
  function safeParse(raw) {
    if (!raw) return [];
    try {
      const parsed = JSON.parse(raw);
      return Array.isArray(parsed) ? parsed : [parsed];
    } catch {
      return [raw];
    }
  }

  // Parse das duas fontes
  const arr1 = safeParse(raw1);
  const arr2 = safeParse(raw2);

  // Une e remove duplicatas mantendo ordem de ocorrência
  const unique = [];
  [...arr1, ...arr2].forEach(msg => {
    if (!unique.includes(msg)) unique.push(msg);
  });

  // Junta numa única conversa
  const conversation = unique.join(' ');

  return [{ json: { conversation } }];
}

// No n8n Function Node, basta retornar:
return mergeUniqueMessages(items);

// Variável de entrada, idealmente verificada
const inputText = $json.output;
let messages = [];

// 1. VERIFICAÇÃO DA ENTRADA
if (typeof inputText !== 'string') {
  // Opção: retornar um erro ou um resultado padrão.
  // Exemplo: retornar mensagens vazias com um erro.
  return [{ json: { messages: [], error: "Input text ($json.output) is not a string or is missing." } }];
  // Se preferir que o script continue com uma string vazia:
  // inputText = "";
}

function isBudget(text) {
  // A verificação de 'text' como string já foi feita no início.
  const orçamentoPalavras = ['orçamento', 'escolher', 'escolhas', 'fechar', 'total geral'];
  const linhas = text.split('\n');
  let blocosDeProduto = 0;

  for (const linha of linhas) {
    if (linha.includes('por R$')) blocosDeProduto++;
  }

  // Compara as palavras chave em minúsculas para robustez
  const contemPalavraChave = orçamentoPalavras.some(p => text.toLowerCase().includes(p.toLowerCase()));
  // Verifica se "Qual dessas você prefere?" aparece pelo menos 2 vezes.
  const contemPerguntaPreferenciaMultipla = (text.split('Qual dessas você prefere?').length -1) >= 2;


  return (
    blocosDeProduto >= 3 ||
    contemPalavraChave ||
    contemPerguntaPreferenciaMultipla
  );
}

function dividirMensagemNatural(texto, limite = 200) {
  // A verificação de 'texto' como string já foi feita.
  // Se o texto estiver vazio após trim, retorna array vazio.
  if (texto.trim().length === 0) {
    return [];
  }

  // Divide o texto em sentenças (partes)
  const partes = texto
    .split(/(?<=[.!?])\s+/g) // Divide após pontuação seguida de espaço
    .map(p => p.trim()) // Remove espaços extras de cada parte
    .filter(p => p.length > 0); // Remove partes vazias

  const mensagensFinais = [];
  let bufferAtual = '';

  for (const parte of partes) {
    // CASO 1: A 'parte' (sentença) sozinha já excede o limite.
    if (parte.length > limite) {
      // Se havia algo no buffer, adiciona-o primeiro às mensagens.
      if (bufferAtual.length > 0) {
        mensagensFinais.push(bufferAtual);
        bufferAtual = ''; // Limpa o buffer
      }

      // Agora, quebra a 'parte' longa.
      // Estratégia: quebrar por palavras.
      let palavrasDaParte = parte.split(/\s+/g).filter(p => p.length > 0);
      let subParteBuffer = '';
      for (const palavra of palavrasDaParte) {
        // Se uma única palavra já excede o limite (e o sub-buffer está vazio)
        if (palavra.length > limite && subParteBuffer.length === 0) {
          mensagensFinais.push(palavra); // Adiciona a palavra longa (pode-se truncar se necessário)
          // subParteBuffer continua vazio para a próxima palavra
        }
        // Tenta adicionar a palavra ao sub-buffer atual
        else if ((subParteBuffer + (subParteBuffer ? ' ' : '') + palavra).length <= limite) {
          subParteBuffer = (subParteBuffer + (subParteBuffer ? ' ' : '') + palavra);
        }
        // Não coube, então descarrega o sub-buffer e inicia um novo com a palavra atual.
        else {
          if (subParteBuffer.length > 0) {
            mensagensFinais.push(subParteBuffer);
          }
          subParteBuffer = palavra; // Esta palavra pode ser > limite, será tratada na próxima iteração ou no push final
        }
      }
      // Adiciona o que sobrou no subParteBuffer da sentença longa
      if (subParteBuffer.length > 0) {
        mensagensFinais.push(subParteBuffer);
      }
      // O buffer principal deve estar vazio aqui, pois a 'parte' longa foi totalmente processada.
      bufferAtual = '';
    }
    // CASO 2: A 'parte' (sentença) NÃO excede o limite por si só.
    else {
      const tentativaComBuffer = (bufferAtual + (bufferAtual ? ' ' : '') + parte);
      if (tentativaComBuffer.length <= limite) {
        // Cabe no buffer atual ou com o buffer atual.
        bufferAtual = tentativaComBuffer;
      } else {
        // Não cabe com o buffer atual. Descarrega o buffer.
        if (bufferAtual.length > 0) {
          mensagensFinais.push(bufferAtual);
        }
        // A 'parte' atual (que sabemos ser <= limite) se torna o novo buffer.
        bufferAtual = parte;
      }
    }
  }

  // Adiciona o que restou no buffer no final de todas as partes.
  if (bufferAtual.length > 0) {
    mensagensFinais.push(bufferAtual);
  }

  return mensagensFinais;
}

// LÓGICA PRINCIPAL
if (isBudget(inputText)) {
  // Se for orçamento, junta tudo numa mensagem, trocando quebras de linha por espaço.
  messages.push(inputText.replace(/\n+/g, ' ').trim());
} else {
  // Senão, divide a mensagem.
  messages = dividirMensagemNatural(inputText, 200); // Limite pode ser passado aqui se diferente do default
}

return [{ json: { messages } }];

// Obtém os valores dos nós anteriores
const sessionid1 = $input.item.json.data;  // Do nó "Gerar sessionID"
const sessionid2 = $input.item.json.sessionid;  // Do nó "Supabase"

// Retorna apenas o que existir, chamando sempre de "sessionId"
return [{ sessionId: sessionid1 || sessionid2 || null }];

// Code node v3 — Run Once for All Items: ON
// Entrada: items[0].json com o JSON da API
// Saída: array de { json: {...} }

function limparTexto(s) {
  return String(s || "").replace(/\s+/g, " ").replace(/[;]+$/g, "").trim();
}
function splitEmails(s) {
  if (!s) return [];
  return String(s).split(/[;,]/).map(x => x.trim()).filter(Boolean);
}
function limparEmail(s) {
  const e = String(s || "").trim().replace(/[;]+$/g, "");
  if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(e)) return "";
  return e.toLowerCase();
}
function normalizePhone(s) {
  if (!s) return "";
  const digits = String(s).replace(/\D/g, "");
  if (digits.length === 10 || digits.length === 11) return digits;
  if (digits.length === 12 || digits.length === 13) {
    const semDDI = digits.replace(/^55/, "");
    if (semDDI.length === 10 || semDDI.length === 11) return semDDI;
  }
  return "";
}
function dedup(arr) { return Array.from(new Set(arr.filter(Boolean))); }
function normalizaData(s) {
  if (!s) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const n = Number(s);
  if (Number.isFinite(n)) {
    const d = new Date(n);
    if (!isNaN(d.getTime())) return d.toISOString().slice(0, 10);
  }
  return null;
}
function toNumber(v) { const n = Number(v); return Number.isFinite(n) ? n : null; }

function formataCEP(s) {
  const d = String(s || "").replace(/\D/g, "");
  if (d.length === 8) return d.slice(0,5) + "-" + d.slice(5);
  return d || null;
}

function montarEnderecoCliente(pedido) {
  const c = pedido?.cliente;
  if (c) {
    const cidadeUF = c?.cidade ? [c.cidade.nomeCidade, c.cidade.siglaEstado].filter(Boolean).join(" ") : "";
    const partes = [
      limparTexto([c.endereco, c.numero].filter(Boolean).join(", ")),
      limparTexto(c.complemento),
      limparTexto(c.bairro),
      limparTexto(cidadeUF),
      formataCEP(c.cep),
    ].filter(Boolean);
    const joined = partes.join(", ").replace(/\s+,/g, ",").trim();
    if (joined) return joined;
  }
  return null;
}

function extrairContatoSimples(pedido) {
  const fones = dedup([
    normalizePhone(pedido?.cliente?.telefone1),
    normalizePhone(pedido?.cliente?.telefone2),
    normalizePhone(pedido?.telefoneConsumidor),
    normalizePhone(pedido?.telefoneCelular),
    normalizePhone(pedido?.enderecoEntrega?.telefone),
  ]);
  const emails = dedup([
    ...splitEmails(pedido?.cliente?.email || ""),
    ...splitEmails(pedido?.cliente?.emailNfe || ""),
    ...splitEmails(pedido?.emailConsumidor || ""),
  ].map(limparEmail));

  return { telefone: fones[0] || null, email: emails[0] || null };
}

function extrairPedidos(pages) {
  const out = [];
  for (const pagina of pages || []) {
    for (const pedido of (pagina?.content || [])) {
      const { telefone, email } = extrairContatoSimples(pedido);
      const nomeCliente = limparTexto(
        pedido?.nomeConsumidorOuCliente ||
        pedido?.cliente?.nome ||
        pedido?.nomeConsumidor ||
        pedido?.cliente?.fantasiaSobrenome ||
        "CONSUMIDOR"
      );
      const vendedor = limparTexto(pedido?.nomeVendedor || "");
      const codigoVendedor = pedido?.codigoVendedor || null;
      const enderecoCliente = montarEnderecoCliente(pedido);

      const dataPedido =
        normalizaData(pedido?.dataUltimaAlteracao) ||
        normalizaData(pedido?.dataEntrega) ||
        normalizaData(pedido?.dataEntrada) ||
        normalizaData(pedido?.dataPrevisaoEntrega) ||
        normalizaData(pedido?.dataOrigem) ||
        null;

      for (const item of (pedido?.itens || [])) {
        const produto = limparTexto(item?.descricaoCompleta || item?.descricaoProduto || "");
        const quantidade = toNumber(item?.quantidade) ?? 1;
        const preco = toNumber(item?.totalItem) ?? 0;

        const dataItem =
          normalizaData(item?.dataFaturamento) ||
          normalizaData(item?.dataEntrada) ||
          dataPedido;

        out.push({
          numeroDocumento: String(pedido?.numeroDocumento || ""),
          nomeCliente,
          enderecoCliente,
          vendedor,
          codigoVendedor,
          produto,
          quantidade,
          preco,
          data: dataItem,
          telefone,
          email,
          codigoAtividade: pedido?.cliente?.codigoAtividade || null,
          nomeVendedor: vendedor || null
        });
      }
    }
  }
  return out;
}

// -------- entrada e retorno --------
let payload = items[0]?.json;
if (payload && payload.body) payload = payload.body;
if (payload && payload.data) payload = payload.data;

const pages = Array.isArray(payload) ? payload : [payload];
const rows = extrairPedidos(pages);

return rows && rows.length ? rows.map(r => ({ json: r })) : [];

// Code node v3 — Run Once for All Items: ON
// Entrada: rows do Code7
// Saída: objeto agrupado por pedido com produtos e total

const pedidos = {};

for (const item of items) {
  const doc = item.json.numeroDocumento;
  if (!doc) continue;

  if (!pedidos[doc]) {
    pedidos[doc] = {
      numeroDocumento: doc,
      nomeCliente: item.json.nomeCliente,
      enderecoCliente: item.json.enderecoCliente,
      vendedor: item.json.vendedor,
      codigoVendedor: item.json.codigoVendedor,
      nomeVendedor: item.json.nomeVendedor,
      numeroLoja:"179",
      telefone: item.json.telefone,
      email: item.json.email,
      data: item.json.data,
      codigoAtividade: item.json.codigoAtividade,
      produtos: [],
      totalPedido: 0
    };
  }

  pedidos[doc].produtos.push({
    produto: item.json.produto,
    quantidade: item.json.quantidade,
    preco: item.json.preco
  });

  pedidos[doc].totalPedido += item.json.preco;
}

// saída formatada
return Object.values(pedidos).map(p => ({ json: p }));

// Função para validar o telefone
function telefoneValido(fone) {
  if (!fone) return false;
  const digits = String(fone).replace(/\D/g, "");
  if (!(digits.length === 10 || digits.length === 11)) return false;
  if (/^(\d)\1+$/.test(digits)) return false;
  const numeroPrincipal = digits.slice(2);
  if (/^9{8,9}$/.test(numeroPrincipal)) return false;
  return true;
}

// Escapa apóstrofos para uso em string SQL
function strToSqlSafe(s) {
  return String(s ?? "").replace(/'/g, "''");
}

// Serializa produtos em JSON e escapa apóstrofos para usar em '...::jsonb'
function jsonToSqlSafeJsonb(value) {
  const json = JSON.stringify(value ?? []);
  return json.replace(/'/g, "''"); // duplica apóstrofo para SQL
}

// Mapeamento de vendedor → telefone
const mapaVendedores = {
  "010": "11999324730", // ANDRÉ
  "014": "11999324730", // RAPHAEL
  "022": "11999324730", // MATHEUS
  "423": "11999324730"  // IGOR NUNES
};

const out = [];

for (const item of items) {
  const p = { ...item.json };

  // filtro 1: ignora CONSUMIDOR
  if (!p.nomeCliente || p.nomeCliente.toUpperCase() === "CONSUMIDOR") continue;

  // filtro 2: ignora telefone inválido
  if (!telefoneValido(p.telefone)) continue;

  // telefone do vendedor
  p.telefoneVendedor = mapaVendedores[p.codigoVendedor] || null;

  // prepara campo seguro para o INSERT em jsonb
  // use este campo no SQL: '{{ $json.produtos_sql }}'::jsonb
  p.produtos_sql = jsonToSqlSafeJsonb(p.produtos);

  // se quiser, já prepare também strings seguras para outros campos com apóstrofo:
  // p.nomeCliente_sql = strToSqlSafe(p.nomeCliente);
  // p.enderecoCliente_sql = strToSqlSafe(p.enderecoCliente);
  // p.vendedor_sql = strToSqlSafe(p.vendedor);

  out.push({ json: p });
}

return out;

// Code node v3 — Run Once for All Items: ON
// Entrada: itens contendo pedidos como você já tem usado
// Saída: analise SOMENTE do dia anterior (America/Sao_Paulo)
// Se "ontem" não existir nos dados, usa a data mais recente disponível

function to2(n) { return Math.round((n + Number.EPSILON) * 100) / 100; }

function ensureArrayFromItems(items) {
  if (!items?.length) return [];
  const j0 = items[0].json;
  if (Array.isArray(j0)) return j0; // primeiro item é o array completo
  return items.map(i => i.json);    // caso comum: um pedido por item
}

function totalPedido(p) {
  return to2((p.produtos || []).reduce((acc, it) => acc + Number(it.preco || 0), 0));
}

function qtdItens(p) {
  return (p.produtos || []).reduce((acc, it) => acc + Number(it.quantidade || 0), 0);
}

function acum(map, key, valor) {
  if (!map[key]) map[key] = 0;
  map[key] += valor;
}

function topN(dict, n, by = 'valor') {
  const arr = Object.entries(dict).map(([k, v]) => {
    if (typeof v === 'number') return { nome: k, valor: v };
    return { nome: k, valor: v.valor ?? 0, qtd: v.qtd ?? 0 };
  });
  arr.sort((a, b) => (b[by] ?? 0) - (a[by] ?? 0));
  return arr.slice(0, n).map(x => ({ ...x, valor: to2(x.valor) }));
}

function ymdInTZ(date) {
  // retorna YYYY-MM-DD em America/Sao_Paulo
  const s = date.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' }); // dd/mm/aaaa
  const [dd, mm, yyyy] = s.split('/');
  return `${yyyy}-${mm.padStart(2,'0')}-${dd.padStart(2,'0')}`;
}

const pedidosRaw = ensureArrayFromItems(items);

// normaliza pedidos
const pedidosOut = pedidosRaw.map(p => ({
  numeroDocumento: p.numeroDocumento,
  data: p.data, // já está em YYYY-MM-DD
  vendedor: p.vendedor || null,
  nomeCliente: p.nomeCliente,
  telefone: p.telefone || null,
  email: p.email || null,
  enderecoCliente: p.enderecoCliente || null,
  qtdProdutos: p.produtos?.length || 0,
  qtdItens: qtdItens(p),
  totalPedido: totalPedido(p),
  produtos: p.produtos || []
}));

// Captura o número da loja (assumindo que todos os pedidos são da mesma loja)
const numeroLoja = pedidosRaw[0]?.numeroLoja || null;

// determina "ontem" em São Paulo
const hojeSP = new Date();
const ontemSP = new Date(hojeSP.getTime() - 24*60*60*1000);
const dataOntem = ymdInTZ(ontemSP);

// define data alvo
const datasDisponiveis = [...new Set(pedidosOut.map(p => p.data))].filter(Boolean).sort();
let dataAlvo = dataOntem;
let usouDataMaisRecente = false;

let pedidosDia = pedidosOut.filter(p => p.data === dataAlvo);

// se não há pedidos no "ontem", usa a última data disponível
if (pedidosDia.length === 0 && datasDisponiveis.length > 0) {
  dataAlvo = datasDisponiveis[datasDisponiveis.length - 1];
  pedidosDia = pedidosOut.filter(p => p.data === dataAlvo);
  usouDataMaisRecente = true;
}

// métricas do dia
const faturamentoTotal = to2(pedidosDia.reduce((a, p) => a + p.totalPedido, 0));
const totalPedidos = pedidosDia.length;
const totalItens = pedidosDia.reduce((a, p) => a + p.qtdItens, 0);
const clientesUnicos = new Set(pedidosDia.map(p => p.nomeCliente || 'SEM NOME')).size;
const ticketMedio = totalPedidos ? to2(faturamentoTotal / totalPedidos) : 0;

// por vendedor (dia)
const porVendValor = {};
const porVendQtd = {};
for (const p of pedidosDia) {
  const vend = p.vendedor || 'SEM VENDEDOR';
  acum(porVendValor, vend, p.totalPedido);
  acum(porVendQtd, vend, 1);
}
const porVendedor = Object.keys(porVendValor).map(v => ({
  vendedor: v,
  pedidos: porVendQtd[v] || 0,
  total: to2(porVendValor[v] || 0),
  ticketMedio: porVendQtd[v] ? to2(porVendValor[v] / porVendQtd[v]) : 0
})).sort((a, b) => b.total - a.total);

// por dia — só a data analisada
const porDia = [{ data: dataAlvo, total: faturamentoTotal }];

// top clientes do dia
const clientesDict = {};
for (const p of pedidosDia) acum(clientesDict, p.nomeCliente || 'SEM NOME', p.totalPedido);
const topClientes = topN(clientesDict, 10, 'valor');

// top produtos do dia
const prodDict = {};
for (const p of pedidosDia) {
  for (const it of (p.produtos || [])) {
    const nome = it.produto || 'SEM PRODUTO';
    if (!prodDict[nome]) prodDict[nome] = { qtd: 0, valor: 0 };
    prodDict[nome].qtd += Number(it.quantidade || 0);
    prodDict[nome].valor += Number(it.preco || 0);
  }
}
const topProdutosQtd = topN(prodDict, 10, 'qtd');
const topProdutosValor = topN(prodDict, 10, 'valor');

// pedidos atípicos no dia: > 2 x ticket médio do dia
const pedidosAtipicos = ticketMedio > 0
  ? pedidosDia.filter(p => p.totalPedido > 2 * ticketMedio).map(p => p.numeroDocumento)
  : [];

const resumo = {
  numeroLoja,
  dataAlvo,
  usouDataMaisRecente,
  faturamentoTotal,
  totalPedidos,
  totalItens,
  clientesUnicos,
  ticketMedio,
  pedidosAtipicos
};

return [
  {
    json: {
      analise: {
        resumo,
        porVendedor,
        porDia,
        topClientes,
        topProdutosQtd,
        topProdutosValor,
        pedidos: pedidosDia
      }
    }
  }
];

// Code Node v3 - Run Once for All Items: OFF
// Entrada: cada item tem "telefone_vendedor"
// Saída: adiciona a propriedade "bearer" no JSON

// Dicionário de mapeamento telefone_vendedor -> bearer
const bearerMap = {
  "11999324730": ""
};

// Processa os itens
return items.map(item => {
  const vendedorFone = item.json.telefone_vendedor;
  const bearer = bearerMap[vendedorFone] || null; // se não achar, null
  return {
    json: {
      ...item.json,
      bearer
    }
  };
});

// Mapeamento de vendedores para bearer tokens
const vendedorBearerMap = {
  "34": "xlq60rj5h6obvilh272bm", // GUILHERME SANTOS
  "23": "vykizy8qcesdhvmemyzca", // FLAVIO REIS
  "22": "7vibmcp4sjaqom8oukx5aa", // THIAGO JESUS SANTOS
  "6": "fazq7sh6av744sihsbrv8j" // FABIO SANTOS DE OLIVEIRA
};

// Pega os items do loop
const items = $input.all();

// Adiciona o bearer token em cada item
return items.map(item => {
  const vendedorId = String(item.json.VENDEDOR); // Converte para string
  const bearer = vendedorBearerMap[vendedorId];

  if (!bearer) {
    throw new Error(`Bearer token não encontrado para vendedor: ${vendedorId}`);
  }

  return {
    json: {
      ...item.json,
      BEARER: bearer
    }
  };
});

